from pydantic import BaseModel, EmailStr, field_validator
from typing import Optional

class Address(BaseModel):
    line1: str
    city: str
    country: str = "US"   # default value

class UserPreferences(BaseModel):
    theme: str = "light"
    language: str = "en-US"

class User(BaseModel):
    user_id: int
    name: str
    email: str
    address: Optional[Address] = None          # address is optional
    preferences: UserPreferences = UserPreferences()  # default if absent
    tags: list[str] = []

    @field_validator("email")
    @classmethod
    def email_must_contain_at(cls, v: str) -> str:
        if "@" not in v:
            raise ValueError("Invalid email address")
        return v.lower()

# Parse and validate a JSON payload from an API
raw = {
    "user_id": 101,
    "name": "Alice Chen",
    "email": "Alice@Example.COM",  # will be lowercased
    "address": {"line1": "10 Elm St", "city": "Boston"}
    # preferences and tags are absent — defaults kick in
}

user = User(**raw)
print(user.email)                  # alice@example.com
print(user.preferences.theme)      # light  (default)
print(user.tags)                   # []     (default)
print(user.address.country)        # US     (default)

# An invalid payload raises a ValidationError
try:
    bad = User(user_id="not-a-number", name="Bob", email="bob@example.com")
except Exception as e:
    print(e)   # user_id: value is not a valid integer

-- Create a table with a JSONB column for flexible user metadata
CREATE TABLE users (
    user_id   SERIAL PRIMARY KEY,
    email     VARCHAR(255) NOT NULL UNIQUE,
    metadata  JSONB
);

-- Insert documents with varying structures
INSERT INTO users (email, metadata) VALUES
('alice@example.com', '{
    "name": "Alice Chen",
    "address": {"city": "Boston", "country": "US"},
    "tags": ["premium", "early-adopter"],
    "preferences": {"theme": "dark"}
}'),
('bob@example.com', '{
    "name": "Bob Patel",
    "address": {"city": "Chicago", "country": "US"}
}');  -- no preferences, no tags — that is fine

-- Query nested field using ->> operator (returns text)
SELECT email, metadata->>'name' AS name
FROM users
WHERE metadata->>'name' IS NOT NULL;

-- Filter on nested city
SELECT email
FROM users
WHERE metadata->'address'->>'city' = 'Boston';

-- Check array membership (does tags contain 'premium'?)
SELECT email
FROM users
WHERE metadata->'tags' ? 'premium';

-- GIN index for efficient JSONB queries
CREATE INDEX idx_users_metadata ON users USING GIN(metadata);

