# ✅ Validate before storing — catch problems at the boundary
from pydantic import BaseModel, ValidationError

class User(BaseModel):
    user_id: int
    name: str
    email: str

def save_user_good(payload: dict):
    try:
        user = User(**payload)
    except ValidationError as e:
        raise ValueError(f"Invalid user payload: {e}") from e
    db.users.insert_one(user.model_dump())

# ❌ Over-embedding — storing full order history inside user document
# Grows unboundedly; updating a single order requires rewriting the full array
user = {
    "user_id": 101,
    "name": "Alice",
    "orders": [
        {"order_id": "o1", "total": 89.99, "status": "delivered", ...},
        {"order_id": "o2", "total": 49.99, "status": "pending", ...},
        # ... 500 more orders over time
    ]
}

# ✅ Reference by ID — orders are their own top-level documents
user = {
    "user_id": 101,
    "name": "Alice"
    # orders NOT embedded here
}
order = {
    "order_id": "o1",
    "user_id": 101,     # reference to user
    "total": 89.99,
    "status": "delivered"
}

// MongoDB — create indexes for common query patterns
// Compound index: category filter + price sort
db.products.createIndex({ category: 1, price_usd: 1 })

// Sparse index: only index documents that have this field
db.products.createIndex({ "specs.ram_gb": 1 }, { sparse: true })

// Text index for full-text search on name and description
db.products.createIndex({ name: "text", description: "text" })

// Check if a query uses an index (returns winning plan)
db.products.find({ category: "electronics", price_usd: { $lt: 1000 } })
           .explain("executionStats")

# ❌ Vulnerable to NoSQL injection — user input used directly in query
def find_user_bad(username: str, password: str):
    return db.users.find_one({"username": username, "password": password})
    # If username = {"$gt": ""}, this matches ALL users regardless of password

# ✅ Validate that inputs are plain strings before querying
def find_user_good(username: str, password: str) -> dict | None:
    if not isinstance(username, str) or not isinstance(password, str):
        raise ValueError("Inputs must be strings")
    return db.users.find_one({"username": username, "password": password})
